ish language competency; GE Area 3B'),(1790,2175,'prerequisite','GE Area 3B; SPAN 301'),(1791,2177,'restriction','Not a Theatre or Theatre Arts major'),(1792,2180,'prerequisite','GE Area 3A'),(1793,2182,'prerequisite','GE Area 3A or GE Area 3B'),(1794,2183,'prerequisite','GE Area 3A'),(1795,2184,'prerequisite','ENGL 101'),(1796,2185,'prerequisite','GE Area 3A'),(1797,2186,'prerequisite','GE Area 3A'),(1798,2187,'prerequisite','GE Area 3B; 300-level VIET course'),(1799,2188,'prerequisite','GE Area 3B'),(1800,2189,'prerequisite','GE Area 3B');
