CREATE TABLE `courses` (
  `id` int NOT NULL AUTO_INCREMENT,
  `course_code` varchar(15) NOT NULL,
  `course_name` varchar(255) DEFAULT NULL,
  `course_description` text,
  `units_min` decimal(3,1) NOT NULL DEFAULT '0.0',
  `units_max` decimal(3,1) NOT NULL DEFAULT '0.0',
  `has_lab` tinyint(1) NOT NULL DEFAULT '0',
  `includes_lab` tinyint(1) NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  UNIQUE KEY `course_code` (`course_code`)
) ENGINE=InnoDB AUTO_INCREMENT=2190 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
