INSERT INTO `courses` VALUES (1,'ACCT 201A','Financial Accounting','Accounting concepts and techniques essential to the administration of a business enterprise: analyzing and recording financial transactions; accounting valuation and allocation practices; preparation, analysis and interpretation of financial statements; international accounting issues.',3.0,3.0,0,0),(2,'ACCT 201B','Managerial Accounting','Introduction to managerial accounting; product costing; budgetary control and responsibility accounting; analysis and techniques for aiding management planning and control decisions; basic income tax concepts for planning business transactions.',3.0,3.0,0,0),(3,'ACCT 301A','Intermediate Accounting','Accounting theory; preparation of income statements, balance sheets, and statements of cash flows and comprehensive income; IFRS (International Financial Reporting Standards); present value concepts; assets, revenue recognition and investments.',3.0,3.0,0,0),(4,'ACCT 301B','Intermediate Accounting','Accounting theory; IFRS (International Financial Reporting Standards); present value concepts; liabilities and stockholders’ equity; pensions; leases; earnings per share; financial statement analysis; accounting changes and error analysis; accounting for income taxes and statement of cash flows.',3.0,3.0,0,0),(5,'ACCT 302','Cost Accounting','Accounting information for management of manufacturing and service enterprises; cost records; cost behavior and allocation; product costing and inventory valuation; flexible budgeting; standard costs; responsibility accounting; cost planning and control; and operating decision analysis.',3.0,3.0,0,0),(6,'ACCT 307','Accounting Information Systems','Organization and implementation of information technology for the collection, organization and presentation of accounting information with an emphasis on enterprise resource planning systems.',3.0,3.0,0,0),(7,'ACCT 308','Concepts of Federal Income Tax Accounting','Federal tax system, federal income taxation relating to federal tax system, federal income taxation relating to individuals, corporations, partnerships and fiduciaries. Federal estate and gift taxes.',3.0,3.0,0,0),(8,'ACCT 401','Advanced Accounting','Business combinations; meaning, usefulness and methodology of consolidated financial statements; investments and additional advanced topics; consolidated financial statements for overseas units of U.S.-based multinational companies; translations of foreign currencies, derivatives.',3.0,3.0,0,0),(9,'ACCT 402','Auditing','Auditing standards and procedures used by financial and operational auditors. Management information and computer systems, internal control, audit evidence, professional responsibilities and legal liabilities, standards of reporting financial information.',3.0,3.0,0,0),(10,'ACCT 403','Accounting for Governmental and Nonprofit Entities','Fund accounting as applied to governmental and nonprofit entities; state and federal governments, municipalities, hospitals and universities. Budgets, tax levies, revenues and appropriations, expenditures and encumbrances, various types of funds and accounting statements.',3.0,3.0,0,0),(11,'ACCT 405','Forensic Accounting and Fraud Examination','Methods to prevent and detect fraud. Current cases dealing with accounting fraud and appropriate methods to prevent or detect fraudulent behavior.',3.0,3.0,0,0),(12,'ACCT 408','Taxation of Business Entities','Additional tax knowledge on tax research, corporate taxation, partnership taxation, S Corps, transfer taxation, gift taxes and accounting for income tax. Other topics, such as SALT, may be included.',3.0,3.0,0,0),(13,'ACCT 420','Advanced Cost Accounting','Advanced topics in accounting: strategic profitability analysis; cost allocation and resources; quality and Just-In Time Inventory; and investment decisions and management control.',3.0,3.0,0,0),(14,'ACCT 422','Internal Audit and Control','Professional standards and procedures used by internal auditors. Planning, performing, communicating risk based assurance and consulting engagements. Advanced topics in control; governance, risk management, fraud and information technology. Requires departmental permission for non-Accounting undergraduate majors and all graduate students.',3.0,3.0,0,0),(15,'ACCT 445','Valuation Concepts and Topics for Accountants','Conceptual framework for valuation. Students will apply the framework in a number of settings they are likely to encounter as accounting professionals (i.e., fair value of financial assets, goodwill impairment).',3.0,3.0,0,0),(16,'ACCT 460','Seminar in Financial Statement Analysis','Analysis of demand and supply forces underlying the provision of financial statements; distributional, cross-sectional and time series properties of financial statement numbers; financial decision-making processes and the uses of financial statement information for decision making.',3.0,3.0,0,0),(17,'ACCT 463','Financial Controls for Entrepreneurs','Accounting system design for new ventures, including budgeting, purchasing, collections, payroll taxes, safeguards against error and embezzlement, financial reports, cash management and banking relationships. Casework, research and fieldwork with selected local businesses.',3.0,3.0,0,0),(18,'ACCT 495','Internship (1-3)','Planned and supervised work experience. May be repeated for a maximum of 6 units. Letter grade or credit/no credit. Requires consent of the department internship adviser and one semester in residence at the university.',1.0,3.0,0,0),(19,'ACCT 499','Independent Study (1-3)','Open to qualified undergraduate students desiring to pursue directed independent inquiry. May be repeated for a maximum of 6 units. Not open to students on academic probation. Requires permission of department chair.',1.0,3.0,0,0),(20,'ACCT 502','Accounting Theory and Professional Research','Provides an analytical framework for managerial decision-making using accounting information. Explore solutions to professional accounting problems by researching the FASB Codification.',3.0,3.0,0,0),(21,'ACCT 503','Seminar in Accounting Data Analytics','Introduction to data extraction, analytic and data visualization tools used in business today, and techniques for Big Data analyses. Hands-on experience with several key tools used to transform raw data into actionable knowledge.',3.0,3.0,0,0),(22,'ACCT 505','Seminar in Auditing','Auditing theory and practices; professional ethics; auditing standards; Securities and Exchange Commission and stock exchange regulations; auditor’s legal liability; statement trends and techniques.',3.0,3.0,0,0),(23,'ACCT 506','Seminar in Professional Accounting Communications','Compilation and composition of accounting reports and client presentations relating to accountants’ working papers, client engagement letters, management advisory reports and prospectuses.',3.0,3.0,0,0),(24,'ACCT 507','Seminar in Accounting Information Systems','Case studies of computer-based accounting systems used by organizations such as universities, banks, industrial corporations and CPA firms. Accounting information, reports, and internal controls.',3.0,3.0,0,0),(25,'ACCT 508','Seminar in Tax Planning','Substantive provisions of federal law; tax planning from a corporate viewpoint; case studies of the effect of federal tax law on business decisions.',3.0,3.0,0,0),(26,'ACCT 510','Financial Accounting','Accumulation, organization and interpretation of financial and quantitative data relevant to the activities of corporate business enterprises; analysis of financial reports; current regulatory reporting requirements with attention to business ethics and an understanding of global reporting issues.',3.0,3.0,0,0),(27,'ACCT 511','Seminar in Managerial Accounting','Design and develop cost accounting systems; contemporary cost management concepts; measurement, analysis and use of accounting information for management decisions with attention to current ethical, global and environmental issues. Measurement, analysis and use of information contained in standard and various cost systems for industry sectors.',3.0,3.0,0,0),(28,'ACCT 521','Advanced Management Accounting and Controls','Integrative aspects of accounting, financial and quantitative data for managerial decision-making; long-term, short-term profit planning; budgetary control; cost analysis; financial analysis and planning; taxation; and transfer pricing.',3.0,3.0,0,0),(29,'ACCT 572','Seminar in Taxation of Corporations and Shareholders Corp. II','Federal taxation relating to corporations; organizing, distributions, liquidations and reorganizations.',3.0,3.0,0,0),(30,'ACCT 573','Seminar in Taxation of Property and M&A Transactions','Concepts, rules and issues with regard to the taxation of transactions involving different types of property. Taxation of property transactions when a buyer acquires another company.',3.0,3.0,0,0),(31,'ACCT 574','Seminar in Taxation of International Business Operations','Federal taxation relating to U.S. citizens and corporations with foreign source income and of foreign persons with U.S. source income; planning for foreign operations.',3.0,3.0,0,0),(32,'ACCT 575','Seminar in Estate, Gift, Inheritance Taxes and Estate Planning','Federal and California death taxes and the planning of personal estates.',3.0,3.0,0,0),(33,'ACCT 576','Seminar in State and Local Taxation','Application of interstate income allocations; multi-state tax compact; separate apportionment accounting; foreign country sourced income. California taxes as applied to businesses and individuals.',3.0,3.0,0,0),(34,'ACCT 577','Seminar in Taxation of Employee Compensation','Federal taxation relating to employee compensation including pensions and profit sharing, stock options, ESOPs, IRAs, Keoghs, maximum tax 5-year averaging, death benefits, group term life, etc.',3.0,3.0,0,0),(35,'ACCT 578','Seminar in Taxation of Flow-Through Entities','Federal taxation relating to partnerships, estates, trusts and other special entities.',3.0,3.0,0,0),(36,'ACCT 580','Seminar in Taxation of S Corporations, LLCs and LLPs','Tax consequences of electing and operating as a Subchapter S Corporation, including entity level taxes, distributions and computation of basis. Terminating the S Corporation election and liquidations.',3.0,3.0,0,0),(37,'ACCT 597','Accounting Capstone - Professional Research Project','Culminating intellectual experience to use knowledge learned. Solve complex accounting problems using analytic tools applied to real world data with guidance from faculty and professionals.',3.0,3.0,0,0),(38,'ACCT 599','Independent Graduate Research (1-3)','May be repeated for credit for a maximum of 6 units. Not open to students on academic notice. Requires approval of department chair and associate dean.',1.0,3.0,0,0),(39,'AFAM 101','Introduction to Ethnic Studies','Perspectives through which people of color have come to see themselves in terms of their own heroes, cultures and contributions to the societies in which they live and the world in general. (AFAM 101, ASAM 101, and CHIC 101 are the same course)',3.0,3.0,0,0),(40,'AFAM 107','Introduction to African American Studies','Introduction to key texts and topics in African American Studies. Interdisciplinary exploration of social conditions, political engagement, intellectual production and cultural contributions of African Americans.',3.0,3.0,0,0),(41,'AFAM 190','Survey of American History with Emphasis on Ethnic Minorities','Survey of American history from prehistoric times (before 1492) to the present with special emphasis on the role of race and ethnicity. (HIST 190, AFAM 190, ASAM 190 and CHIC 190 are the same course.)',3.0,3.0,0,0),(42,'AFAM 301','African American Food Culture','Dynamic relationship between African Americans, food culture and food in the U.S. from their earliest beginnings; focusing on the socio-historical, creative, economic and geographic manifestations of the relationship between food culture, identity and wellness.',3.0,3.0,0,0),(43,'AFAM 304','Black Families in America','Issues of race, class, gender, sexuality and identity within African American families. Topics will include: black single mothers and welfare, prisons, black middle class families and residential housing, black youth and activism, and LGBT family formations. (AFAM 304 and SOCI 304 are the same course.)',3.0,3.0,0,0),(44,'AFAM 307','Research and Writing in Ethnic Studies','Introduction to research and writing in ethnic studies. Issues of research in ethnic studies (e.g., quantitative v. qualitative analysis, reliability/validity) and specific methods of research (e.g., archives, interviews, oral history). Extensive writing. A “C” (2.0) or better is required to satisfy the upper-division writing requirement. (ASAM 307, AFAM 307 and CHIC 307 are the same course.)',3.0,3.0,0,0),(45,'AFAM 308','Black Men in America','The diverse and conflicting representations and theories of black masculinity in the U.S. and abroad. Explores tensions between representations and social, economic, and political realities of black men. Analyzes contemporary issues of black masculinities and the post-racial imaginary.',3.0,3.0,0,0),(46,'AFAM 310','Black Women in America','Issues in the study of black women in America, including social, political, economic and intellectual development. Historical and contemporary issues as they affect black American women. (AFAM 310 and GSS 310 are the same course.)',3.0,3.0,0,0),(47,'AFAM 311','Race and Relationships','How race, ethnicity, gender and class matter in everyday society, emphasizing intrapersonal relationships, racial socialization and the effects of this racial socialization in people’s lives.',3.0,3.0,0,0),(48,'AFAM 314','Pan-African Dance and Movement','Theory and practice of movement of African and Haitian peoples. Movement (dance) as quasi-language in perpetuating the life style of African cultures and cultures of African descent.',3.0,3.0,0,0),(49,'AFAM 320','Black Political Thought','The black American intellectual from slavery to contemporary times, emphasizing black contributions to American political and social thought, as well as their contributions in America’s social development.',3.0,3.0,0,0),(50,'AFAM 321','Activism, Engagement and Professional Development','Planning and community development trends in minority communities in urban, suburban and rural areas. Theoretical perspectives and practices embraced by grassroots planners. Public and private sector approaches. Topics include neighborhood planning, community development, economic development and grassroots organizing.',3.0,3.0,0,0),(51,'AFAM 322','Black Psychology','Uses psychological principles and practices to guide students’ comprehension of life as an African American. Introduction to a holistic perspective that expands ways of conceptualizing psychology from an African American world view. (AFAM 322 and PSYC 322 are the same course.)',3.0,3.0,0,0),(52,'AFAM 324','Introduction to African American Literature','Literary contributions by major black American authors. Contemporary black writers and the recurring themes of protest and quest for identity. (AFAM 324 and ENGL 324 are the same course.)',3.0,3.0,0,0),(53,'AFAM 325','African American Religions and Spirituality','African-American belief systems and denominations. Folk beliefs among Blacks, African-American religious groups and the role of the Black Church in politics and social change in the Black community. (AFAM 325 and RLST 325 are the same course.)',3.0,3.0,0,0),(54,'AFAM 335','History of Racism','Historical roots and current expressions of racism. How racism manifests itself through individual, social, political, economic and religious institutions and proposes methods of combating it.',3.0,3.0,0,0),(55,'AFAM 356','African American Music Appreciation','Black music in America; the sociological conditions that help produce various forms of black music. (AFAM 356 and MUS 356 are the same course)',3.0,3.0,0,0),(56,'AFAM 357','Blacks in the Performing Arts','African-American culture through the performing arts. Blacks in the entertainment industry as a means of understanding and revealing important aspects of African-American culture. (AFAM 357, MUS 357 and THTR 357 are the same course.)',3.0,3.0,0,0),(57,'AFAM 405','Black Representations in Film','Critical study of black images in motion pictures, past and present. The tension between historical Black consciousness, authenticity, imitation and alternative adaptations.',3.0,3.0,0,0),(58,'AFAM 499','Independent Study (1-3)','May be repeated for a maximum of 6 units. Requires acceptance of the subject by department chair and instructor directing the study.',1.0,3.0,0,0),(59,'AMST 101','Questioning America','What is American culture? Introduction to multiple methods used to understand ideas of America and American culture; explore diverse techniques to investigate questions of power, belonging and everyday life.',3.0,3.0,0,0),(60,'AMST 201','Introduction to American Studies','With the concept of culture as a unifying principle, focus is on four separate time periods in order to provide the framework for an understanding of American civilization. Several different kinds of documents will be used to illustrate the nature and advantages of an interdisciplinary approach.',3.0,3.0,0,0),(61,'AMST 300','Introduction to American Popular Culture','Historical exploration of popular culture in America as it reflects and contributes to the search for meaning in everyday life. Heroes, myths of success, symbols of power, images of romance, consumerism, race and sexual identity.',3.0,3.0,0,0),(62,'AMST 301','American Experiences','American identities and beliefs, through a sampling of historical and contemporary voices from different groups of Americans. Similarities and differences in Americans¿ experiences based on class, race, ethnicity, gender, sexuality, region and other identities.',3.0,3.0,0,0),(63,'AMST 320','Women in American Society','Socio-cultural history of women and women’s movements in American society. Emphasis on 19th and 20th centuries. Cultural models of American womanhood - maternal, domestic, sexual, social - their development and recent changes.',3.0,3.0,0,0),(64,'AMST 345','The American Dream','Interdisciplinary analysis, in settings both historical and contemporary, of the myth and reality surrounding the notion of America as a land of unparalleled and unlimited possibilities, especially in the achievement of personal material success.',3.0,3.0,0,0),(65,'AMST 350','Seminar in Theory and Method of American Studies','Understanding and appreciation of methodology, theories of society and images of humanity as they affect American studies contributions to scholarship. Fulfills the course requirement of the university upper-division baccalaureate writing requirement for American Studies majors.',3.0,3.0,0,0),(66,'AMST 377','Prejudice and American Culture','Concepts and methods of American culture studies as tools for better understanding the origins and appeal of intolerance, past and present. Particular focus on racism, ethnic and religious bias, sexism and homophobia.',3.0,3.0,0,0),(67,'AMST 395','California Cultures','Who can claim to be Californian? The ideals and realities of what it means to be Californian; investigating how various identities ¿ of race, class, gender, sexuality, region and generation ¿ have interacted in California¿s cultures, past and present.',3.0,3.0,0,0),(68,'AMST 401T','Proseminar in American Studies','Relationship between theory and application. Analytic readings and research. Check the class schedule for topics being considered. May be repeated once for credit with different topic.',3.0,3.0,0,0),(69,'AMST 413','The Shifting Role and Image of the American Male','Effect of economic, social, political and cultural changes on American males. Emphasizes 19th and 20th centuries.',3.0,3.0,0,0),(70,'AMST 419','Love in America','Changes in the emotional lives of American men and women from the 17th century to the present. Enduring and innovative views on the nature of love and the cultural forces that shape its legitimate and illegitimate expression.',3.0,3.0,0,0),(71,'AMST 420','Childhood and Family in American Culture','Historical and contemporary culture study of childhood and family in America. The idea of childhood, changing concepts of child-rearing, growing up in the American past, the impact of modernization, mother and home as dominant cultural symbols.',3.0,3.0,0,0),(72,'AMST 438','American Minds: Images of Sickness and Health','Cultural changes in American images of the healthy mind. Medical and legal views of insanity, Freud’s impact on American thought, literary treatments of madness and psychological themes in American popular culture.',3.0,3.0,0,0),(73,'AMST 473','Sexual Orientations and American Culture','Cultural construction of the very idea of a sexual orientation. Shifting meanings of erotic attraction and involvement in America, especially regarding people of the same sex, from the colonial period to the present.',3.0,3.0,0,0),(74,'AMST 499','Independent Study (1-3)','Supervised research projects in American Studies to be taken with the consent of instructor and department chair. May be repeated for a maximum of 6 units.',1.0,3.0,0,0),(75,'AMST 501','Theory and Methods','The American Studies movement. Its conceptual and methodological development. The way this development was affected by and in turn reflected larger trends in the culture itself.',3.0,3.0,0,0),(76,'AMST 502T','Seminar: Selected Topics','A particular problem or topic as a case study in the use of interdisciplinary methods in American studies. May be repeated once for credit with different topic.',3.0,3.0,0,0),(77,'AMST 596','American Studies Teaching Tutorial','Preparation for community college or university teaching. Small group discussion, lecture-discussion, examinations and teaching strategies. Enrollment requires approval of American Studies graduate coordinator. Course may be repeated for credit, but may only count once on a graduate study plan.',3.0,3.0,0,0),(78,'AMST 598','Thesis','Writing of a thesis based on original research and its analysis and evaluation. Requires consent of graduate coordinator.',3.0,3.0,0,0),(79,'AMST 599','Independent Graduate Research (1-3)','May be repeated for a maximum of 6 units. Requires consent of graduate coordinator.',1.0,3.0,0,0),(80,'ANTH 100','Non-Western Cultures and the Western Tradition','Changing views of people, nature and culture in Western civilization as related to the impact of non-Western influences, including the use and interpretation of data on non-Western peoples and cultures.',3.0,3.0,0,0),(81,'ANTH 101','Introduction to Biological Anthropology','Humans as biological organisms from an evolutionary perspective. Concepts, methods, findings and issues in the study of the Order primates, including the relationships among fossil monkeys, apes and humans, and the significance of genetic diversity in modern populations.',3.0,3.0,0,0),(82,'ANTH 102','Introduction to Cultural Anthropology','Nature of culture and its significance. Similarities and difference in human cultures. Analyses of family, economy, subsistence, religion, art and other aspects of culture in diverse societies. Central problems of cultural comparison and interpretation.',3.0,3.0,0,0),(83,'ANTH 103','Introduction to Archaeology','Relationship of archaeology, culture history and process, field methods and analysis of archaeological data; uses and abuses of archaeology.',3.0,3.0,0,0),(84,'ANTH 105','Introduction to Anthropology','Introduction to basic aspects of anthropology’s sub-fields (biological anthropology, archaeological anthropology, cultural anthropology, and linguistic anthropology), and to an anthropological view of the world, which is grounded in a respect for cultural differences.',3.0,3.0,0,0),(85,'ANTH 300','Language and Culture','Language in the context of culture. The symbolic nature of language, speech as performance, non-verbal communication, gendered speech and bias in language. Language acquisition, language change and loss, and factors leading to the invention of writing.',3.0,3.0,0,0),(86,'ANTH 304','Traditional Cultures of the World','Comparative, worldwide survey of traditional, selected and well-studied ways of life using ethnographic writings and films. Examines diverse ways of life, with an emphasis on small-scale societies.',3.0,3.0,0,0),(87,'ANTH 305','Anthropology of Religion','Beliefs and practices in the full human variation of religious phenomena, with an emphasis on primitive religions. Forms, functions, structures, symbolism, and history and evolution of religious systems. (ANTH 305 and RLST 305 are the same course.)',3.0,3.0,0,0),(88,'ANTH 306','Culture and Art','Explores different types of creative expression and arts within the cultural context of diverse societies, including such forms as painting, weaving, stories, myths, music, dance, masks, body decoration and sculpture, among others.',3.0,3.0,0,0),(89,'ANTH 308','Culture and Aging: Anthropological Gerontology','Anthropological discourse on diverse cultural conceptions of aging as they relate to gender, class, ethnic and religious categories. Cross-cultural comparison of culturally patterned time-table of life-cycle and age-grades for understanding the universals and variability in human aging.',3.0,3.0,0,0),(90,'ANTH 310','Urban Anthropology','Cross-cultural investigation of similarities and differences in urbanism with an emphasis on current theoretical and methodological perspectives in the study of social and cultural forms and processes in urban populations.',3.0,3.0,0,0),(91,'ANTH 311','Culture and Communication','How meanings are created, exchanged and interpreted in both traditional and modern cultures through language, myth and religion, art and architecture, and other means of communication.',3.0,3.0,0,0),(92,'ANTH 313','Psychological Anthropology','Relationship of culture to the individual. Child-training in non-western cultures. Survey of concepts, studies and research techniques in psychological anthropology.',3.0,3.0,0,0),(93,'ANTH 315','Culture and Nutrition','Interrelationships among human nutrition, basic food resources, individual development and socio-cultural organization; includes assessment of student’s nutritional status, beliefs and practices relative to other cultures.',3.0,3.0,0,0),(94,'ANTH 316','Anthropology of Sex and Gender','Human sex and gender roles in cross-cultural perspective and the role that gender plays in human social organization. Topics covered include cultural construction of gender; homosexuality, rights of women, evolution and gender. (ANTH 316 and GSS 316 are the same course.)',3.0,3.0,0,0),(95,'ANTH 321','Peoples of Native North America','Native peoples of North America; origins, languages, culture areas, cultural history; the impact of European contacts.',3.0,3.0,0,0),(96,'ANTH 325','Peoples of Central and South America','Cultural survey of South America. Representative cultural areas before and after contacts with Western countries.',3.0,3.0,0,0),(97,'ANTH 327','Origins of Civilizations','Development of civilization in the Old and New Worlds in primary centers such as Mesopotamia, Egypt, the Indus Valley, China, Mesoamerica and Peru, and secondary centers such as the Aegean and Europe.',3.0,3.0,0,0),(98,'ANTH 329','Peoples of the Caribbean','Various ethnic groups of the Caribbean, focusing on the description and interpretation of African, European, Asian and Amerindian cultural elements.',3.0,3.0,0,0),(99,'ANTH 332','Gender in Cross-Cultural Perspectives','Cross-cultural comparison of beliefs, values, and expectations related to gender roles in diverse societies. Changes in social definitions and perspectives of gender in the contemporary world.',3.0,3.0,0,0),(100,'ANTH 340','Peoples of Asia','Asian civilizations and cultural traditions: personality configurations in different culture areas; structure of Asian civilizations; and peasant, tribal and ethnic groups of Asia.',3.0,3.0,0,0),(101,'ANTH 342','Anthropology and Health','Uses an evolutionary, comparative and cross-cultural perspective to understand the process and conception of health in different times, places and societies. Topics include: evolutionary medicine, health beliefs, health ecology, culture and health. Computer labs utilizing eHRAF.',3.0,3.0,0,0),(102,'ANTH 343','Human Osteology','Techniques in basic identification of human skeletal remains. Aging, sexing, racing and stature reconstruction. For those interested in archaeology, hominid evolution and/or forensic science. (2 hours lecture, 3 hours laboratory)',3.0,3.0,0,0),(103,'ANTH 344','Sex, Evolution and Human Nature','Evolutionary theory and human evolution; the primate origins of humanity, the evolution of human nature, and the evolutionary foundations of human behavior and cognition.',3.0,3.0,0,0),(104,'ANTH 347','Archaeology and Cultures of Pacific Islands','Indigenous peoples, cultures and archaeology of Pacific Islands, including Tahiti, Hawaii and Australia. Forces and processes contributing to social change in island communities and contemporary problems being faced by them.',3.0,3.0,0,0),(105,'ANTH 350','Culture and Education','Transmission of values, implicit cultural assumptions and the patterning of education in cross-cultural perspective. American culture and development problems.',3.0,3.0,0,0),(106,'ANTH 423','The Ancient Maya','Archaeology and ethnohistory of the Maya area of Southern Mesoamerica. Problems of initial settlement of the area and the rise and dynamics of ancient Maya civilization.',3.0,3.0,0,0),(107,'ANTH 424','The Aztecs and Their Predecessors','Archaeological survey of principal Mesoamerica pre-Columbian cultures north and west of the Maya area. Aztecs and their predecessors, religion, art, architecture, intellectual achievements and the Olmec heritage.',3.0,3.0,0,0),(108,'ANTH 401','Ethnographic Field Methods','Anthropological field research by students on various problems using participant observation techniques.',3.0,3.0,0,0),(109,'ANTH 402','Museum Science','Methods, principles and techniques used in natural history, and small scientific and historical museums. Scope of exhibit and research collections, care and repair of specimens, acquisitions, storage and preparation of presentations in anthropological, historical, biological and paleontological museums.',3.0,3.0,0,0),(110,'ANTH 403','Archaeological Fieldwork','Excavation of a local archaeological site. Archaeological mapping, photography and recording. Laboratory methods of cataloging, preservation, description and interpretation of archaeological materials. Saturday field sessions. May be repeated once for credit as an elective. (1 hour lecture, 6 hours laboratory)',3.0,3.0,0,0),(111,'ANTH 404','Analytical Methods in Archaeology','Employing physical data collecting techniques (e.g., photographic, paleomagnetic) in the field, and analyzing artifact collections and data from previous field operations in the laboratory. May be repeated once for credit as an elective. (1 hour lecture, 6 hours laboratory)',3.0,3.0,0,0),(112,'ANTH 406','Descriptive Linguistics','Sounds (phonology), forms and meanings (morphology), and syntax of languages. Examples and problem-solving in various languages. (LING 406 and ANTH 406 are the same course.)',3.0,3.0,0,0),(113,'ANTH 414','Economic Anthropology','Ethnology and ethnography of economic life, principally in non-Western societies; operation of systems of production and distribution within diverse cultural contexts.',3.0,3.0,0,0),(114,'ANTH 415','Anthropology of Tourism','Tourism and travel as cultural practices. Domestic and international tourism; perspective of hosts and travelers; global economy and tourism; souvenirs, artifacts and symbolic landscapes; tourism as pilgrimage.',3.0,3.0,0,0),(115,'ANTH 416','Anthropological Linguistics','Nature and functions of language; language structure and change; classification of languages; use of linguistic evidence in anthropology. (ANTH 416 and LING 416 are the same course.)',3.0,3.0,0,0),(116,'ANTH 420','Visual Anthropology','Development of the field of visual anthropology and the changing and diverse approaches to the use of visual media in representing and interpreting other cultures.',3.0,3.0,0,0),(117,'ANTH 441','Human Variation','Processes underlying and the theories for the existence of the present variation between and within human populations. Genetics of human populations and the significance of racial classifications. (2 hours lecture, 3 hours laboratory)',3.0,3.0,0,0),(118,'ANTH 443','Advanced Topics in Human Osteology','Analytical methods stressing morphological examination of human bone in a laboratory setting (determination of human, prehistoric; analysis of fragmented and commingled remains; basic identification and report writing; pathological conditions). For those interested in archaeology, hominid evolution and/or forensic science.',3.0,3.0,0,0),(119,'ANTH 445','Quantitative Methods in Anthropology','Develops skills and knowledge in the application of quantitative methods in anthropological research. Integrated approach to research design, data collection, data management and data analysis through hands-on training.',3.0,3.0,0,0),(120,'ANTH 451','Advanced Evolutionary Anthropology','Uses life history theory to examine the evolutionary ecology of human behavior. Human life course, resource acquisition, parenting and fertility. Computer labs utilizing eHRAF. (ANTH 451 and BIOL 451 are the same course.)',3.0,3.0,0,0),(121,'ANTH 453','Human Evolutionary Anatomy','Uses an evolutionary framework to conduct an in-depth and detailed examination of the structure and function of human anatomical systems, their interaction, and their evolutionary histories and how those histories affect health in modern populations.',3.0,3.0,0,0),(122,'ANTH 454','Primate Conservation','Uses behavioral ecology and life history theory to understand issues surrounding conservation of non human primates. Develop theoretical background crucial to understanding the population dynamics and ecological principles driving primate conservation strategies.',3.0,3.0,0,0),(123,'ANTH 480','History of Anthropology','Principal contributions of anthropologists 1850-1950; evolutionary, diffusionist, historical, particularist, configurationalist, and culture and personality approaches in anthropology.',3.0,3.0,0,0),(124,'ANTH 481','Contemporary Anthropology','Anthropologists from 1950 to present; neoevolutionist, sociological, structuralist, psychological and symbolic approaches.',3.0,3.0,0,0),(125,'ANTH 490T','Undergraduate Seminar in Anthropology','Topics in anthropology. May be repeated once for credit with a different topic.',3.0,3.0,0,0),(126,'ANTH 491','Internship in Anthropology','Career opportunities. On-the-job training under faculty supervision in museum, industry or governmental service. One or more papers required. May be repeated once for credit.',3.0,3.0,0,0),(127,'ANTH 498','Museum Practicum','Practical experience in museum operations, using the facilities of the Anthropology Museum. Exhibit preparation, membership and funding operations, catalogue preparation and outreach activities. May be repeated once for credit.',3.0,3.0,0,0),(128,'ANTH 499','Independent Study (1-3)','Individual research project involving either library or fieldwork. Conferences with the adviser as necessary. Results in one or more papers. May be repeated for a maximum of six units. Requires consent of adviser.',1.0,3.0,0,0),(129,'ANTH 507','Grammatical Analysis','Word formation in a variety of languages with emphasis on the terminology used to describe morphological representation on various levels; problem solving of selected language data. (LING 507 and ANTH 507 are the same course.)',3.0,3.0,0,0),(130,'ANTH 510','Research Design in Anthropology','